head.script:
/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	scwin.param = JSON.parse($p.getPopupParam());
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPB1300000");
	scwin.searchDatas();
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 이미지 변경 함수 호출
	scwin.imgProcss();
};

/**
 * 발전원별 사업추진절차 이미지를 변경한다.
 * @param
 * @return
 */
scwin.imgProcss = function() {
	if (scwin.param.setcscNm == "태양광") {
		imgProcss.setSrc("/resources/images/ecs/pb/snpw_procss.png");
	} else if (scwin.param.setcscNm == "소수력") {
		imgProcss.setSrc("/resources/images/ecs/pb/smlhp_procss.png");
	} else if (scwin.param.setcscNm == "수열") {
		imgProcss.setSrc("/resources/images/ecs/pb/wtht_procss.png");
	}
};
